import { useNavigate } from 'react-router-dom';
import logo from '../assets/blouge.svg';
import '../styles/Navbar.css';



export default function Navbar({ darkMode, setDarkMode }) {
    const navigate = useNavigate();

    return (
        <nav className="navbar-container">
            <div className="navbar-left" onClick={() => navigate('/groups')}>
                <img src={logo} alt="Blouge Logo" className="nav-logo" />
            </div>

            <div className="navbar-center">
                <button onClick={() => navigate('/groups')} className="nav-button">
                    Home
                </button>

                <button onClick={() => setDarkMode()} className="nav-button">
                    {darkMode ? '☀️ Mode Clair' : '🌙 Mode Sombre'}
                </button>
            </div>

            <div className="navbar-right">
                <button onClick={() => navigate('/')} className="logout-button">
                    Déconnexion
                </button>
            </div>
        </nav>
    );
}
